// frontend/src/components/Dashboard/PNLCard.js
import React from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton
} from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import './PNLCard.css';


const PNLCard = ({ data, loading, hideValues = false, stats = null }) => {
  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);
    // Para valores muito pequenos (< 0.01), usar mais casas decimais
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `$${numValue.toFixed(6)}`;
    }
    // Para valores pequenos (< 1), usar 4 casas decimais
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(4)}`;
    }
    // Para valores maiores, usar 2 casas decimais
    return `$${numValue.toFixed(2)}`;
  };

  const formatPercentage = (value) => {
    // Percentuais permanecem visíveis
    if (value === null || value === undefined) return '0.00%';
    const sign = value >= 0 ? '+' : '';
    return `${sign}${parseFloat(value).toFixed(2)}%`;
  };

  if (loading) {
    return (
      <Paper 
        sx={{ 
          p: 3, 
          height: 380,
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center'
        }}
      >
        <Skeleton variant="text" width="60%" height={40} />
        <Skeleton variant="text" width="80%" height={60} sx={{ mt: 2 }} />
        <Skeleton variant="text" width="40%" height={30} sx={{ mt: 1 }} />
      </Paper>
    );
  }

  // Priorizar dados das estatísticas se disponíveis, senão usar curva de lucro
  let currentPnL, realizedPnL, unrealizedPnL, pnlChange, pnlChangePercent;

  if (stats) {
    // Usar dados das estatísticas (mais precisos)
    currentPnL = stats.total_pnl || 0;
    realizedPnL = stats.realized_pnl || 0;
    unrealizedPnL = stats.unrealized_pnl || 0;

    // Calcular variação baseada no P&L realizado vs não realizado
    pnlChange = unrealizedPnL;
    pnlChangePercent = realizedPnL !== 0 ? ((unrealizedPnL / Math.abs(realizedPnL)) * 100) : 0;
  } else {
    // Fallback para curva de lucro
    currentPnL = data && data.length > 0 ? data[data.length - 1]?.cumulative_pnl || 0 : 0;
    const previousPnL = data && data.length > 1 ? data[data.length - 2]?.cumulative_pnl || 0 : 0;
    realizedPnL = currentPnL;
    unrealizedPnL = 0;
    pnlChange = currentPnL - previousPnL;
    pnlChangePercent = previousPnL !== 0 ? ((pnlChange / Math.abs(previousPnL)) * 100) : 0;
  }

  const isPositive = currentPnL >= 0;
  const isProfitable = currentPnL > 0;
  const isLoss = currentPnL < 0;
  const isSevereLoss = currentPnL < -100; // Prejuízo severo para efeito de raios

  // Componente para efeito de sol
  const SunEffect = () => (
    <div className="sun-effect" />
  );

  // Componente para efeito de chuva
  const RainEffect = () => (
    <div className="rain-effect">
      {[...Array(15)].map((_, i) => (
        <div key={i} className="rain-drop" />
      ))}
    </div>
  );

  // Componente para efeito de raios
  const LightningEffect = () => (
    <div className="lightning-effect" />
  );

  // Componente para ondas do oceano
  const OceanWaves = () => (
    <div className="ocean-waves" />
  );

  return (
    <Paper 
      className={`pnl-card-background ${
        isProfitable ? 'ocean-sunny positive-glow' : 
        isLoss ? 'ocean-stormy negative-shadow' : 
        'ocean-sunny'
      }`}
      sx={{ 
        p: 3,
        height: 380,
        borderRadius: 2,
        color: 'white',
        position: 'relative',
        overflow: 'hidden'
      }}
    >
      {/* Efeitos de fundo animados */}
      {isProfitable && <SunEffect />}
      {isLoss && <RainEffect />}
      {isSevereLoss && <LightningEffect />}
      <OceanWaves />

      <Box 
        className="pnl-card-content"
        sx={{ 
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-between',
          position: 'relative',
          zIndex: 15
        }}
      >
        {/* Header */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          {isPositive ? (
            <TrendingUp sx={{ color: '#4caf50', fontSize: 28 }} />
          ) : (
            <TrendingDown sx={{ color: '#f44336', fontSize: 28 }} />
          )}
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 600,
              textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
            }}
          >
            P&L Total
          </Typography>
        </Box>

        {/* Main PNL Value */}
        <Box sx={{ textAlign: 'center', my: 2 }}>
          <Typography 
            variant="h3" 
            sx={{ 
              fontWeight: 700,
              color: isPositive ? '#4caf50' : '#f44336',
              textShadow: '2px 2px 4px rgba(0,0,0,0.8)',
              mb: 1
            }}
          >
            {formatCurrency(currentPnL)}
          </Typography>

          <Typography 
            variant="h5" 
            sx={{ 
              fontWeight: 600,
              color: pnlChangePercent >= 0 ? '#4caf50' : '#f44336',
              textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
            }}
          >
            {formatPercentage(pnlChangePercent)}
          </Typography>
        </Box>

        {/* Footer Info */}
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Box>
            <Typography 
              variant="caption" 
              sx={{ 
                color: 'rgba(255,255,255,0.8)',
                textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
              }}
            >
              {stats ? 'P&L Realizado' : 'Variação Diária'}
            </Typography>
            <Typography 
              variant="body2" 
              sx={{ 
                fontWeight: 600,
                color: (stats ? realizedPnL : pnlChange) >= 0 ? '#4caf50' : '#f44336',
                textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
              }}
            >
              {formatCurrency(stats ? realizedPnL : pnlChange)}
            </Typography>
          </Box>

          <Box sx={{ textAlign: 'right' }}>
            <Typography 
              variant="caption" 
              sx={{ 
                color: 'rgba(255,255,255,0.8)',
                textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
              }}
            >
              {stats ? 'P&L Não Realizado' : 'Status'}
            </Typography>
            <Typography 
              variant="body2" 
              sx={{ 
                fontWeight: 600,
                color: stats ? 
                  (unrealizedPnL >= 0 ? '#4caf50' : '#f44336') : 
                  (isPositive ? '#4caf50' : '#f44336'),
                textShadow: '1px 1px 2px rgba(0,0,0,0.7)'
              }}
            >
              {stats ? formatCurrency(unrealizedPnL) : (isPositive ? 'LUCRO' : 'PREJUÍZO')}
            </Typography>
          </Box>
        </Box>
      </Box>
    </Paper>
  );
};

export default PNLCard;
